-- Team Performance (team): delivery, quality, outcomes, adaptability. Feeds the
-- Health board's Performance axis.
insert into public.assessment_template (workspace_id, key, name, category, scope, source, description, definition)
select null, 'team_performance', 'Team Performance', 'performance', 'team',
  'OwnTheAgenda original · team performance (delivery, quality, outcomes, adaptability)',
  'How well the team performs: delivery on commitments, quality, outcomes vs goals, and adaptability.',
  $j${"scale":{"min":1,"max":7,"minLabel":"Strongly disagree","maxLabel":"Strongly agree"},"strengthDimension":"outcomes","dimensions":[{"key":"delivery","label":"Delivery","blurb":"Do we deliver on our commitments and timelines?"},{"key":"quality","label":"Quality","blurb":"Is the quality of our work consistently high?"},{"key":"outcomes","label":"Outcomes","blurb":"Do we achieve our goals and real impact?"},{"key":"improvement","label":"Adaptability","blurb":"Do we improve and adapt as conditions change?"}],"items":[{"key":"del_1","dimension":"delivery","text":"We consistently deliver on our commitments."},{"key":"del_2","dimension":"delivery","text":"We meet our deadlines and milestones."},{"key":"qual_1","dimension":"quality","text":"The quality of our work meets a high standard."},{"key":"qual_2","dimension":"quality","text":"We rarely have to redo work because of errors or rework."},{"key":"out_1","dimension":"outcomes","text":"We achieve the goals and outcomes we set."},{"key":"out_2","dimension":"outcomes","text":"Our work delivers real impact for our customers and stakeholders."},{"key":"imp_1","dimension":"improvement","text":"We continuously improve how we work."},{"key":"imp_2","dimension":"improvement","text":"We adapt quickly when priorities or conditions change."}]}$j$::jsonb
where not exists (select 1 from public.assessment_template where workspace_id is null and key='team_performance');
